document.querySelectorAll(".js-logout-form").forEach(e=>{e.addEventListener("submit",async e=>{e.preventDefault();const t=document.querySelector('meta[name="_csrf"]')?.getAttribute("content"),o=document.querySelector('meta[name="_csrf_header"]')?.getAttribute("content"),n={};t&&o&&(n[o]=t);try{await fetch("/api/auth/logout",{method:"POST",credentials:"same-origin",headers:n})}finally{window.location.href="/login"}})});